import React from 'react';
import logoBlanco from '../../assets/logo/Logo-auto-blanco.png';
import { 
    AppBar, 
    Container, 
    Toolbar, 
    Typography, 
    Button,
    Box
} from "@mui/material";


const Navbar = (props) => {

    return (
    <AppBar position="static" sx={{ backgroundColor: "#33489E" }}>
        <Container>
            <Toolbar>
                <Box sx={{display: "flex", alignItems}}>
                    <img src={logoBlanco} alt="logo" className="logo" height={50}/>
                    <Typography variant="h4" component="div" sx={{ flexGrow: 1, fontWeight: "500",color: "whitesmoke", fontFamily: "Roots" }}>
                        LavAutos
                    </Typography>
                </Box>
                <Typography variant="body2" component="div" sx={{ flexGrow: 1, color: "whitesmoke", fontStyle: "italic" }}>
                    {props.subTitle}
                </Typography>
                <div className="buttonHeader">
                    <Button onClick={props.onClick}>
                        {props.linkName}    
                    </Button>
                </div>
            </Toolbar>
        </Container>
    </AppBar>
    )
}
export default Navbar
